#include "mlpa/analyzers/Analyzers.h"
#include <clang/AST/RecursiveASTVisitor.h>
namespace mlpa { namespace { SourceLocation loc(const clang::SourceManager&s,clang::SourceLocation l){auto p=s.getPresumedLoc(l);return{p.isValid()?p.getFilename():"<unknown>",p.isValid()?p.getLine():0,p.isValid()?p.getColumn():0};} void issue(AnalysisResult&r,const clang::SourceManager&s,clang::SourceLocation l,std::string id,Severity sev,std::string title,std::string exp,std::string fix){r.issues.push_back({std::move(id),Category::ModernCpp,sev,loc(s,l),std::move(title),std::move(exp),std::move(fix)});} class V: public clang::RecursiveASTVisitor<V>{public:V(clang::ASTContext&c,AnalysisResult&r):ctx(c),res(r),sm(c.getSourceManager()){} bool VisitGNUNullExpr(clang::GNUNullExpr*e){issue(res,sm,e->getBeginLoc(),"MOD001",Severity::Low,"Use nullptr","NULL is not type-safe in overload resolution.","Replace NULL with nullptr.");return true;} bool VisitTypedefDecl(clang::TypedefDecl*d){issue(res,sm,d->getLocation(),"MOD002",Severity::Low,"Prefer using aliases","using aliases are clearer and support alias templates.","Replace typedef with a using declaration.");return true;} bool VisitCXXMethodDecl(clang::CXXMethodDecl*m){if(m->size_overridden_methods()>0&&!m->hasAttr<clang::OverrideAttr>()) issue(res,sm,m->getLocation(),"MOD004",Severity::Medium,"Missing override","An overriding virtual function should declare override so signature drift is caught.","Add the override specifier.");return true;} bool VisitCXXConstructorDecl(clang::CXXConstructorDecl*c){ if(c->isConvertingConstructor(false)&&!c->isExplicit()) issue(res,sm,c->getLocation(),"MOD005",Severity::Medium,"Converting constructor should be explicit","Implicit single-argument conversions can create surprising temporaries.","Mark the constructor explicit unless implicit conversion is intentional."); return true;} bool VisitParmVarDecl(clang::ParmVarDecl*p){ if(!p->getType()->isReferenceType()&&p->getType().isConstQualified()==false&&p->getType()->isPointerType()) issue(res,sm,p->getLocation(),"MOD003",Severity::Low,"Consider const correctness","Pointer parameters that are not modified should communicate const intent.","Use const-qualified pointee or reference types where possible."); return true;}private:clang::ASTContext&ctx;AnalysisResult&res;const clang::SourceManager&sm;};}
void ModernCppAnalyzer::analyze(clang::ASTContext &context, AnalysisResult &result){V(context,result).TraverseDecl(context.getTranslationUnitDecl());}}
